import{M as e,g as t,p as n}from"./chunks/runtime-core.esm-bundler.hCTfDbu2.js";import{t as r}from"./chunks/plugin-vue_export-helper.Di2WtTEh.js";var i=JSON.parse(`{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"introduce.md","filePath":"introduce.md","lastUpdated":1780578554000}`),a={name:`introduce.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h1><p><code>@vaebe/ccui</code> 是一套基于 <strong>Vue 3 + TypeScript</strong> 的开箱即用组件库，视觉与心智模型对齐 <a href="https://ant-design.antgroup.com/" target="_blank" rel="noreferrer">Ant Design v6</a>，覆盖通用 / 布局 / 导航 / 数据录入 / 数据展示 / 反馈 / 其他七类、80+ 个组件。</p><h2 id="设计取向" tabindex="-1">设计取向 <a class="header-anchor" href="#设计取向" aria-label="Permalink to “设计取向”">​</a></h2><ul><li><strong>对标而非照搬</strong>：能力覆盖到、迁移成本低，但 React-only 的 API 形态（render props / forwardRef / 静态属性挂子组件等）会全部翻译成 Vue 习惯（slot、<code>v-model:*</code>、平铺导出）。详见 <a href="https://github.com/vaebe/ccui/blob/main/docs-notes/decisions/benchmark-principles.md" target="_blank" rel="noreferrer">对标原则</a>。</li><li><strong>TypeScript 优先</strong>：完整 <code>.d.ts</code> 类型导出，组件 props / events / slots 全量可推导。</li><li><strong>主题原生 CSS 变量</strong>：SeedToken / MapToken 双层体系，CSS 变量挂 <code>:root</code>，切换 <code>.dark</code> 类即启用暗色。</li><li><strong>可访问性</strong>：浮层 / 选择 / 列表 / 录入 等关键组件已完成 ARIA + 键盘审计。</li><li><strong>国际化</strong>：内置 zhCN / enUS / jaJP / koKR 四个语言包，<code>ConfigProvider</code> 切换同步驱动 dayjs locale 按需懒加载。</li></ul><h2 id="主题-token" tabindex="-1">主题 Token <a class="header-anchor" href="#主题-token" aria-label="Permalink to “主题 Token”">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>默认值</th></tr></thead><tbody><tr><td>colorPrimary</td><td><code>#1677ff</code></td></tr><tr><td>colorSuccess</td><td><code>#52c41a</code></td></tr><tr><td>colorWarning</td><td><code>#faad14</code></td></tr><tr><td>colorError</td><td><code>#ff4d4f</code></td></tr><tr><td>colorInfo</td><td><code>#1677ff</code></td></tr><tr><td>borderRadius</td><td><code>6px</code>（large 8 / small 4）</td></tr><tr><td>fontSize</td><td><code>14px</code>（行高 1.5714）</td></tr><tr><td>controlHeight</td><td><code>32px</code>（large 40 / small 24）</td></tr></tbody></table><p>CSS 变量同时挂载到 <code>:root</code> 和 SCSS 变量 fallback，可直接通过 <code>var(--ccui-color-primary)</code> 等方式消费；切换到 <code>.dark</code> 类即可启用暗色主题。完整 token 列表与定制方式见 <a href="/ccui/components/config-provider/">ConfigProvider 全局配置</a>。</p><h2 id="浏览器支持" tabindex="-1">浏览器支持 <a class="header-anchor" href="#浏览器支持" aria-label="Permalink to “浏览器支持”">​</a></h2><p>跟随 Vue 3 官方支持范围：现代浏览器、不再支持 IE11。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><ul><li>安装与引入方式见 <a href="/ccui/quick-start.html">快速开始</a></li><li>给 AI / Copilot 接入 ccui 的索引文件见 <a href="/ccui/for-ai.html">AI 接入</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};